var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"강적이군. 이 몸이 한 번도 유효타를 먹이지 못하다니.","JPN":"強敵だな。オレ様が一発も攻撃を当てられないとは。","ENG":"A formidable foe. I haven't been able to get a hit in her once.","TWN":"好強，我完全打不到她。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안…… 나도 마찬가지야.","JPN":"ごめん……僕もだ。","ENG":"Sorry... Me too.","TWN":"抱歉……我也是。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"뭐해? 기세 좋게 등장 해놓고 벌써 지쳤어?","JPN":"何やってるの？　威勢よく登場しておいて、もうダウン？","ENG":"Hmm? Tired already? So you're all talk but no walk, eh?","TWN":"幹嘛？剛才出場時不是很有氣勢嗎？這麼快就累啦？"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 아직 안 끝났다고.","JPN":"ちっ、まだこれからだぜ。","ENG":"Tch! It’s not over yet!","TWN":"嘖，才沒有！"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"가지고 노는 건 그쯤해라, 레노어. 곧 손님이 올 테니.","JPN":"遊ぶのはその辺にしておけ、レノア。もうすぐ客人が来る。","ENG":"Lenore, stop wasting time. Our guests will arrive shortly.","TWN":"適可而止，蕾諾雅。客人就快到了。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"네, 아버지.","JPN":"はい、お父様。","ENG":"Yes, father.","TWN":"是，父親。"},"stage":{"bg":"NANAHARA_SEAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……됐다. 이만 가자.","JPN":"……よし。もう行くぞ。","ENG":"...All right. Let's go.","TWN":"……算了，我們走吧。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예? 갑자기 어디로 간다는 말씀이십니까?","JPN":"え？　急にどちらに行かれるのですか？","ENG":"Huh? Where are we going?","TWN":"什麼？為什麼突然說要走？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"당주들이 패배한 뒤엔, 이곳 영지 또한 위험해진다.","JPN":"当主たちが負けたら、ここの領地も危険になる。","ENG":"Once the leaders of the families are defeated, the lands themselves will be in danger.","TWN":"堂主們失敗後，領地這裡也會變得很危險。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"여기서 다 죽을 수는 없는 노릇 아니냐?","JPN":"ここで皆殺しになるわけにはいかないじゃろう？","ENG":"We can't all die here, can we?","TWN":"總不能大家一起死在這裡吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"정 불안하다면 도망칠 것이 아니라 도우러 가야지요!","JPN":"不安なら逃げるのではなく、助けに行くべきでしょう！","ENG":"If you are that anxious, we should be there helping them! Not running away!","TWN":"如果您真的擔心，就應該去幫忙，而不是逃跑！"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"너, 나나하라 당주의 명령을 무시할 셈이냐?","JPN":"お主、七原当主の命令を無視するつもりか？","ENG":"Are you telling me that you're going to disobey Lady Nanahara's orders?","TWN":"你，打算無視七原堂主的命令嗎？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"말했을 텐데?","JPN":"言ったはずじゃ。","ENG":"Have I not made it clear?","TWN":"我應該有說過吧？"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"역신베기의 완성을 미루는 한이 있더라도, 나나하라 가문의 직계는 존속되어야 한다.","JPN":"大蛇薙剣の完成を後回しにしてでも、七原家の直系は残さなければならぬ。","ENG":"Even if we risk delaying the completion of Orochinagi, the Nanahara lineage must be preserved.","TWN":"就算可以暫緩完成瘟神斬的計畫，但前提是七原家族的直系必須活著。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그러니 네놈도 이제 당주의 무사 노릇은 그만둬.","JPN":"お主ももう当主の護衛はやめることじゃ。","ENG":"So, whatever you're thinking of doing, don't.","TWN":"所以，你現在要卸下堂主的武士一職。"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예정에 없던 아이가 태어나, 역신을 깨우리라……","JPN":"前例のない子どもが生まれ、疫病神の眠りを覚ますだろう……","ENG":"The unexpected child... shall awaken the Plague God.","TWN":"不在預期內出生的孩子，會喚醒瘟神……"},"stage":{"bg":"NANAHARA_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};